queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?source_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSources ?child ; p:hasEnvironment_And_Energy_Reporters ?parent . } GROUP BY ?child }
  ?child p:source_name ?source_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Environment_And_Energy_Reporters } }
  FILTER(?nf = ?total)
}

